{
  "name": "FinIntel India PWA",
  "description": "AI-Powered Financial News Intelligence PWA for the Indian Market. Aggregates news, analyzes impact, and tracks watchlist relevance."
}

export interface NewsItem {
  id: string;
  title: string;
  link: string;
  pubDate: string;
  source: string;
  contentSnippet: string;
  isoDate: Date;
}

export enum ImpactDirection {
  BULLISH = 'Bullish',
  BEARISH = 'Bearish',
  NEUTRAL = 'Neutral',
}

export enum ImpactLevel {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
}

export interface AIAnalysis {
  summary: string; // TL;DR
  whyItMatters: string;
  sectors: string[];
  relatedStocks: string[]; // List of Tickers/Names
  impact: {
    direction: ImpactDirection;
    level: ImpactLevel;
    confidence: number;
  };
  watchlistRelevance?: {
    isRelevant: boolean;
    reason: string;
  };
}

export interface AnalyzedNewsItem extends NewsItem {
  analysis?: AIAnalysis;
  isAnalyzing: boolean;
  analysisError?: boolean;
}

export type ViewState = 'feed' | 'watchlist' | 'settings';

export const RSS_FEEDS = [
  {
    name: 'Economic Times',
    url: 'https://economictimes.indiatimes.com/markets/stocks/rssfeeds/2146842.cms',
  },
  {
    name: 'MoneyControl',
    url: 'https://www.moneycontrol.com/rss/business.xml',
  },
  {
    name: 'Mint',
    url: 'https://www.livemint.com/rss/markets',
  },
];

export const PROXY_URL = 'https://api.allorigins.win/get?url=';

export const STOCK_SUGGESTIONS = [
  'HDFC Bank', 'Reliance Industries', 'Infosys', 'TCS', 
  'ICICI Bank', 'Tata Motors', 'ITC', 'SBI', 'Bajaj Finance',
  'Adani Enterprises', 'Wipro', 'HCL Tech', 'Maruti Suzuki'
];

import { NewsItem } from '../types';
import { RSS_FEEDS, PROXY_URL } from '../constants';

export const fetchNews = async (): Promise<NewsItem[]> => {
  let allNews: NewsItem[] = [];

  const fetchFeed = async (feedUrl: string, sourceName: string) => {
    try {
      const response = await fetch(`${PROXY_URL}${encodeURIComponent(feedUrl)}`);
      const data = await response.json();

      if (!data.contents) return [];

      const parser = new DOMParser();
      const xml = parser.parseFromString(data.contents, 'text/xml');
      const items = xml.querySelectorAll('item');

      const feedItems: NewsItem[] = [];

      items.forEach((item) => {
        const title = item.querySelector('title')?.textContent || '';
        const link = item.querySelector('link')?.textContent || '';
        const pubDateStr = item.querySelector('pubDate')?.textContent || '';
        const description = item.querySelector('description')?.textContent || '';

        // Basic cleanup of description (remove HTML tags often found in RSS)
        const cleanDesc = description.replace(/<[^>]*>?/gm, '').slice(0, 200) + '...';

        if (title && link) {
          feedItems.push({
            id: btoa(link), // Simple ID generation
            title,
            link,
            pubDate: pubDateStr,
            source: sourceName,
            contentSnippet: cleanDesc,
            isoDate: new Date(pubDateStr)
          });
        }
      });
      return feedItems;
    } catch (error) {
      console.error(`Error fetching feed ${sourceName}:`, error);
      return [];
    }
  };

  const promises = RSS_FEEDS.map(feed => fetchFeed(feed.url, feed.name));
  const results = await Promise.all(promises);

  results.forEach(feedItems => {
    allNews = [...allNews, ...feedItems];
  });

  // Sort by date descending
  return allNews.sort((a, b) => b.isoDate.getTime() - a.isoDate.getTime());
};

import { GoogleGenAI, Type } from "@google/genai";
import { AIAnalysis, ImpactDirection, ImpactLevel } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeArticle = async (
  title: string, 
  snippet: string, 
  userWatchlist: string[]
): Promise<AIAnalysis> => {

  const model = "gemini-3-flash-preview";

  const prompt = `
    Analyze this financial news article for the Indian Stock Market context.

    Article Title: "${title}"
    Snippet: "${snippet}"
    User Watchlist: ${JSON.stringify(userWatchlist)}

    Tasks:
    1. Summarize the news in 3-4 bullet lines (TL;DR).
    2. Explain "Why this matters" in 1-2 lines.
    3. Identify 3-4 relevant Indian business sectors.
    4. Identify potentially affected Indian stock tickers/company names (NSE/BSE).
    5. Determine market sentiment (Bullish/Bearish/Neutral) and impact level.
    6. Check if it affects any stock in the User Watchlist. If yes, explain why.

    Return JSON only.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            whyItMatters: { type: Type.STRING },
            sectors: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            relatedStocks: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            impact: {
              type: Type.OBJECT,
              properties: {
                direction: { type: Type.STRING, enum: [ImpactDirection.BULLISH, ImpactDirection.BEARISH, ImpactDirection.NEUTRAL] },
                level: { type: Type.STRING, enum: [ImpactLevel.LOW, ImpactLevel.MEDIUM, ImpactLevel.HIGH] },
                confidence: { type: Type.NUMBER }
              }
            },
            watchlistRelevance: {
              type: Type.OBJECT,
              properties: {
                isRelevant: { type: Type.BOOLEAN },
                reason: { type: Type.STRING }
              }
            }
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as AIAnalysis;
    }
    throw new Error("No text response from AI");
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

const WATCHLIST_KEY = 'finintel_watchlist_v1';

export const getWatchlist = (): string[] => {
  try {
    const stored = localStorage.getItem(WATCHLIST_KEY);
    return stored ? JSON.parse(stored) : [];
  } catch (e) {
    return [];
  }
};

export const addToWatchlist = (stock: string): string[] => {
  const current = getWatchlist();
  if (!current.includes(stock)) {
    const updated = [...current, stock];
    localStorage.setItem(WATCHLIST_KEY, JSON.stringify(updated));
    return updated;
  }
  return current;
};

export const removeFromWatchlist = (stock: string): string[] => {
  const current = getWatchlist();
  const updated = current.filter(s => s !== stock);
  localStorage.setItem(WATCHLIST_KEY, JSON.stringify(updated));
  return updated;
};

