import React from 'react';
import { AnalyzedNewsItem, ImpactDirection, ImpactLevel } from '../types';
import { IconTrendingUp, IconTrendingDown, IconMinus, IconSparkles } from './Icons';

interface NewsCardProps {
  item: AnalyzedNewsItem;
  onAnalyze: (id: string) => void;
}

const NewsCard: React.FC<NewsCardProps> = ({ item, onAnalyze }) => {
  const { analysis, isAnalyzing, analysisError } = item;

  const getImpactColor = (direction: ImpactDirection) => {
    switch (direction) {
      case ImpactDirection.BULLISH: return 'text-bullish bg-emerald-400/10 border-emerald-400/20';
      case ImpactDirection.BEARISH: return 'text-bearish bg-red-400/10 border-red-400/20';
      default: return 'text-neutral bg-slate-400/10 border-slate-400/20';
    }
  };

  const getImpactIcon = (direction: ImpactDirection) => {
    switch (direction) {
      case ImpactDirection.BULLISH: return <IconTrendingUp className="w-4 h-4 mr-1" />;
      case ImpactDirection.BEARISH: return <IconTrendingDown className="w-4 h-4 mr-1" />;
      default: return <IconMinus className="w-4 h-4 mr-1" />;
    }
  };

  return (
    <div className="bg-surface rounded-xl p-4 mb-4 border border-slate-700/50 shadow-sm relative overflow-hidden">
      {/* Watchlist Highlight */}
      {analysis?.watchlistRelevance?.isRelevant && (
        <div className="absolute top-0 right-0 bg-primary/20 text-primary text-[10px] font-bold px-2 py-1 rounded-bl-lg uppercase tracking-wider">
          In Watchlist
        </div>
      )}

      {/* Header */}
      <div className="flex justify-between items-start mb-2">
        <span className="text-[10px] text-slate-400 font-medium uppercase tracking-wider bg-slate-900 px-2 py-0.5 rounded">
          {item.source}
        </span>
        <span className="text-[10px] text-slate-500">
           {new Date(item.pubDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric', hour: '2-digit', minute:'2-digit' })}
        </span>
      </div>

      <h3 className="text-base font-semibold text-slate-100 mb-2 leading-tight">
        {item.title}
      </h3>

      {/* Analysis Section or Analyze Action */}
      {!analysis && !isAnalyzing && (
        <div className="mt-3">
          <p className="text-sm text-slate-400 mb-3 line-clamp-2">
            {item.contentSnippet}
          </p>
          <button 
            onClick={() => onAnalyze(item.id)}
            className="w-full flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 active:bg-slate-800 text-slate-200 text-sm font-medium py-2 rounded-lg transition-colors border border-slate-600"
          >
            <IconSparkles className="w-4 h-4 text-purple-400" />
            Analyze Impact
          </button>
          {analysisError && <p className="text-xs text-red-400 mt-2 text-center">Analysis failed. Please try again.</p>}
        </div>
      )}

      {isAnalyzing && (
        <div className="mt-3 py-4 flex flex-col items-center justify-center space-y-2 bg-slate-900/30 rounded-lg animate-pulse">
           <IconSparkles className="w-5 h-5 text-purple-400 animate-spin" />
           <span className="text-xs text-slate-400">Analyzing market data...</span>
        </div>
      )}

      {analysis && (
        <div className="mt-4 animate-fadeIn">
          {/* Sentiment Badge */}
          <div className={`inline-flex items-center px-2 py-1 rounded-md border text-xs font-semibold mb-3 ${getImpactColor(analysis.impact.direction)}`}>
            {getImpactIcon(analysis.impact.direction)}
            {analysis.impact.direction} • {analysis.impact.level} Impact
          </div>

          {/* Core Analysis */}
          <div className="space-y-3 text-sm">
            <div className="bg-slate-900/50 p-3 rounded-lg border border-slate-700/30">
                <p className="text-slate-300 mb-2"><span className="text-purple-400 font-semibold">TL;DR:</span> {analysis.summary}</p>
                <p className="text-slate-400 text-xs italic"><span className="text-blue-400 font-semibold">Why it matters:</span> {analysis.whyItMatters}</p>
            </div>

            {/* Watchlist Context */}
            {analysis.watchlistRelevance?.isRelevant && (
                <div className="bg-primary/10 p-2 rounded-lg border border-primary/20">
                    <p className="text-xs text-blue-200">
                        <span className="font-bold">⚠️ Watchlist Alert:</span> {analysis.watchlistRelevance.reason}
                    </p>
                </div>
            )}

            {/* Tags */}
            <div className="flex flex-wrap gap-1.5 mt-2">
              {analysis.relatedStocks.map(stock => (
                <span key={stock} className="text-[10px] bg-slate-700 text-slate-200 px-2 py-0.5 rounded-full border border-slate-600">
                  {stock}
                </span>
              ))}
              {analysis.sectors.map(sector => (
                 <span key={sector} className="text-[10px] bg-slate-800 text-slate-400 px-2 py-0.5 rounded-full">
                 #{sector}
               </span>
              ))}
            </div>
          </div>

          <a href={item.link} target="_blank" rel="noopener noreferrer" className="block mt-3 text-xs text-center text-slate-500 hover:text-slate-300 underline">
            Read full article on {item.source}
          </a>
        </div>
      )}
    </div>
  );
};

export default NewsCard;

import React, { useState, useEffect, useCallback } from 'react';
import { fetchNews } from './services/newsService';
import { analyzeArticle } from './services/geminiService';
import { addToWatchlist, getWatchlist, removeFromWatchlist } from './services/storageService';
import { AnalyzedNewsItem, ViewState } from './types';
import { STOCK_SUGGESTIONS } from './constants';
import NewsCard from './components/NewsCard';
import { IconHome, IconList, IconPlus, IconSparkles, IconTrash } from './components/Icons';

const App = () => {
  const [activeView, setActiveView] = useState<ViewState>('feed');
  const [news, setNews] = useState<AnalyzedNewsItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<string[]>([]);
  const [newStockInput, setNewStockInput] = useState('');

  // Load initial data
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      const savedWatchlist = getWatchlist();
      setWatchlist(savedWatchlist);

      const items = await fetchNews();

      // Initialize news state with "isAnalyzing" false
      const initialNews: AnalyzedNewsItem[] = items.map(item => ({
        ...item,
        isAnalyzing: false
      }));

      setNews(initialNews);
      setLoading(false);

      // Auto-analyze top 2 items to populate dashboard
      if (initialNews.length > 0) {
        // We use a small timeout to let the UI render first
        setTimeout(() => {
           handleAnalyze(initialNews[0].id, savedWatchlist, initialNews);
        }, 500);
         setTimeout(() => {
           if(initialNews[1]) handleAnalyze(initialNews[1].id, savedWatchlist, initialNews);
        }, 2000);
      }
    };
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleAnalyze = async (id: string, currentWatchlist: string[], currentNewsState = news) => {
    const itemIndex = currentNewsState.findIndex(n => n.id === id);
    if (itemIndex === -1) return;

    // Prevent double analysis
    if (currentNewsState[itemIndex].analysis || currentNewsState[itemIndex].isAnalyzing) return;

    // Set analyzing state
    setNews(prev => prev.map(n => n.id === id ? { ...n, isAnalyzing: true, analysisError: false } : n));

    try {
      const item = currentNewsState[itemIndex];
      const analysis = await analyzeArticle(item.title, item.contentSnippet, currentWatchlist);

      setNews(prev => prev.map(n => n.id === id ? { ...n, isAnalyzing: false, analysis: analysis } : n));
    } catch (e) {
      setNews(prev => prev.map(n => n.id === id ? { ...n, isAnalyzing: false, analysisError: true } : n));
    }
  };

  const handleAddToWatchlist = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!newStockInput.trim()) return;
    const updated = addToWatchlist(newStockInput.trim().toUpperCase());
    setWatchlist(updated);
    setNewStockInput('');
  };

  const handleRemoveFromWatchlist = (stock: string) => {
    const updated = removeFromWatchlist(stock);
    setWatchlist(updated);
  };

  // Filter news for watchlist view
  const watchlistNews = news.filter(n => {
    // Show if already analyzed and relevant OR if raw text contains watchlist keyword (fallback)
    if (n.analysis?.watchlistRelevance?.isRelevant) return true;

    // Simple fallback check before AI analysis
    const textToCheck = (n.title + ' ' + n.contentSnippet).toLowerCase();
    return watchlist.some(stock => textToCheck.includes(stock.toLowerCase()));
  });

  return (
    <div className="min-h-screen bg-background text-slate-100 pb-20">

      {/* Top Bar */}
      <div className="sticky top-0 z-20 bg-background/80 backdrop-blur-md border-b border-slate-800 p-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-tr from-blue-600 to-purple-600 flex items-center justify-center">
             <IconSparkles className="text-white w-5 h-5" />
          </div>
          <h1 className="font-bold text-lg tracking-tight">FinIntel<span className="text-primary font-light">India</span></h1>
        </div>
        <div className="text-xs text-slate-500 font-mono">MVP v1.0</div>
      </div>

      {/* Main Content */}
      <main className="p-4 max-w-lg mx-auto w-full">

        {loading ? (
          <div className="flex flex-col items-center justify-center mt-20 space-y-4">
             <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
             <p className="text-slate-400 text-sm">Fetching markets data...</p>
          </div>
        ) : (
          <>
            {/* FEED VIEW */}
            {activeView === 'feed' && (
              <div className="space-y-4 animate-fadeIn">
                 <div className="flex items-center justify-between mb-2">
                    <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Latest Headlines</h2>
                    <span className="text-xs text-slate-600">{news.length} updates</span>
                 </div>

                 {news.map(item => (
                   <NewsCard 
                      key={item.id} 
                      item={item} 
                      onAnalyze={(id) => handleAnalyze(id, watchlist)} 
                   />
                 ))}
              </div>
            )}

            {/* WATCHLIST VIEW */}
            {activeView === 'watchlist' && (
              <div className="animate-fadeIn">
                <div className="mb-6 bg-surface p-4 rounded-xl border border-slate-700">
                  <h2 className="text-lg font-semibold mb-4">My Watchlist</h2>

                  {/* Add Stock */}
                  <form onSubmit={handleAddToWatchlist} className="flex gap-2 mb-4">
                    <input 
                      type="text" 
                      value={newStockInput}
                      onChange={(e) => setNewStockInput(e.target.value)}
                      placeholder="e.g. RELIANCE, TCS" 
                      className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-sm focus:outline-none focus:border-primary text-white placeholder-slate-500"
                    />
                    <button type="submit" className="bg-primary hover:bg-blue-600 text-white p-2 rounded-lg transition-colors">
                      <IconPlus />
                    </button>
                  </form>

                  {/* Chips */}
                  <div className="flex flex-wrap gap-2">
                    {watchlist.length === 0 && <span className="text-slate-500 text-sm italic">No stocks added yet.</span>}
                    {watchlist.map(stock => (
                      <div key={stock} className="flex items-center gap-1 bg-slate-800 border border-slate-600 text-xs px-3 py-1.5 rounded-full">
                        <span className="font-medium text-slate-200">{stock}</span>
                        <button onClick={() => handleRemoveFromWatchlist(stock)} className="text-slate-400 hover:text-red-400">
                           <IconTrash className="w-3 h-3" />
                        </button>
                      </div>
                    ))}
                  </div>

                  {/* Suggestions */}
                  {watchlist.length < 3 && (
                     <div className="mt-4 pt-4 border-t border-slate-700/50">
                        <p className="text-xs text-slate-500 mb-2">Suggestions:</p>
                        <div className="flex flex-wrap gap-2">
                           {STOCK_SUGGESTIONS.slice(0, 5).filter(s => !watchlist.includes(s.toUpperCase())).map(s => (
                              <button 
                                key={s} 
                                onClick={() => {
                                   const updated = addToWatchlist(s.toUpperCase());
                                   setWatchlist(updated);
                                }}
                                className="text-[10px] bg-slate-900 text-slate-400 border border-slate-800 px-2 py-1 rounded hover:border-slate-600"
                              >
                                + {s}
                              </button>
                           ))}
                        </div>
                     </div>
                  )}
                </div>

                <div className="flex items-center justify-between mb-2">
                    <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Watchlist News</h2>
                 </div>

                 {watchlistNews.length > 0 ? (
                    watchlistNews.map(item => (
                      <NewsCard 
                          key={item.id} 
                          item={item} 
                          onAnalyze={(id) => handleAnalyze(id, watchlist)} 
                       />
                    ))
                 ) : (
                   <div className="text-center py-10 text-slate-500">
                      <p>No recent news matched your watchlist.</p>
                      <p className="text-xs mt-1">Try adding broader terms like "BANK" or "AUTO".</p>
                   </div>
                 )}
              </div>
            )}
          </>
        )}
      </main>

      {/* Bottom Nav */}
      <nav className="fixed bottom-0 left-0 w-full bg-background/90 backdrop-blur-lg border-t border-slate-800 pb-safe">
        <div className="flex justify-around items-center p-2 max-w-lg mx-auto">
          <button 
            onClick={() => setActiveView('feed')}
            className={`flex flex-col items-center p-2 rounded-lg w-16 transition-all ${activeView === 'feed' ? 'text-primary' : 'text-slate-500'}`}
          >
            <IconHome className={activeView === 'feed' ? 'stroke-[2.5px]' : ''} />
            <span className="text-[10px] mt-1 font-medium">Feed</span>
          </button>

          <button 
            onClick={() => setActiveView('watchlist')}
            className={`flex flex-col items-center p-2 rounded-lg w-16 transition-all ${activeView === 'watchlist' ? 'text-primary' : 'text-slate-500'}`}
          >
            <IconList className={activeView === 'watchlist' ? 'stroke-[2.5px]' : ''} />
            <span className="text-[10px] mt-1 font-medium">Watchlist</span>
          </button>
        </div>
      </nav>

      <style>{`
        .pb-safe { padding-bottom: env(safe-area-inset-bottom, 20px); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fadeIn { animation: fadeIn 0.4s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

