import React from 'react';
import { FilterState, ImpactDirection, ImpactLevel } from '../types';
import { IconX } from './Icons';

interface FilterPanelProps {
  filters: FilterState;
  setFilters: React.Dispatch<React.SetStateAction<FilterState>>;
  availableSources: string[];
  availableSectors: string[];
  onClose: () => void;
  resultCount: number;
}

const FilterPanel: React.FC<FilterPanelProps> = ({
  filters,
  setFilters,
  availableSources,
  availableSectors,
  onClose,
  resultCount
}) => {

  const toggleSelection = <T extends string>(
    list: T[],
    item: T,
    key: keyof FilterState
  ) => {
    const exists = list.includes(item);
    const updated = exists 
      ? list.filter(i => i !== item)
      : [...list, item];

    setFilters(prev => ({ ...prev, [key]: updated }));
  };

  const clearFilters = () => {
    setFilters({
      sources: [],
      sectors: [],
      impactLevels: [],
      sentiments: []
    });
  };

  const hasFilters = filters.sources.length > 0 || filters.sectors.length > 0 || filters.impactLevels.length > 0 || filters.sentiments.length > 0;

  return (
    <div className="bg-surface border-b border-slate-700 p-4 animate-fadeIn shadow-lg">
      <div className="flex items-center justify-between mb-4">
        <h3 className="font-semibold text-slate-200">Filters</h3>
        <div className="flex gap-4 items-center">
            {hasFilters && (
                <button onClick={clearFilters} className="text-xs text-primary hover:text-blue-400">
                    Clear All
                </button>
            )}
            <button onClick={onClose}>
                <IconX className="w-5 h-5 text-slate-400" />
            </button>
        </div>
      </div>

      <div className="space-y-4 max-h-[60vh] overflow-y-auto no-scrollbar pb-4">

        {/* Sources */}
        <div>
          <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Sources</h4>
          <div className="flex flex-wrap gap-2">
            {availableSources.map(source => (
              <button
                key={source}
                onClick={() => toggleSelection(filters.sources, source, 'sources')}
                className={`text-xs px-3 py-1.5 rounded-full border transition-colors ${
                  filters.sources.includes(source)
                    ? 'bg-primary text-white border-primary'
                    : 'bg-slate-900 text-slate-400 border-slate-700 hover:border-slate-500'
                }`}
              >
                {source}
              </button>
            ))}
          </div>
        </div>

        {/* Sentiment */}
        <div>
          <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Sentiment</h4>
          <div className="flex flex-wrap gap-2">
            {[ImpactDirection.BULLISH, ImpactDirection.BEARISH, ImpactDirection.NEUTRAL].map(sentiment => (
              <button
                key={sentiment}
                onClick={() => toggleSelection(filters.sentiments, sentiment, 'sentiments')}
                className={`text-xs px-3 py-1.5 rounded-full border transition-colors ${
                  filters.sentiments.includes(sentiment)
                    ? 'bg-purple-600 text-white border-purple-600'
                    : 'bg-slate-900 text-slate-400 border-slate-700 hover:border-slate-500'
                }`}
              >
                {sentiment}
              </button>
            ))}
          </div>
        </div>

        {/* Impact Level */}
        <div>
          <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Impact Level</h4>
          <div className="flex flex-wrap gap-2">
            {[ImpactLevel.HIGH, ImpactLevel.MEDIUM, ImpactLevel.LOW].map(level => (
              <button
                key={level}
                onClick={() => toggleSelection(filters.impactLevels, level, 'impactLevels')}
                className={`text-xs px-3 py-1.5 rounded-full border transition-colors ${
                  filters.impactLevels.includes(level)
                    ? 'bg-emerald-600 text-white border-emerald-600'
                    : 'bg-slate-900 text-slate-400 border-slate-700 hover:border-slate-500'
                }`}
              >
                {level}
              </button>
            ))}
          </div>
        </div>

        {/* Sectors */}
        {availableSectors.length > 0 && (
          <div>
            <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Sectors (Analyzed News)</h4>
            <div className="flex flex-wrap gap-2">
              {availableSectors.map(sector => (
                <button
                  key={sector}
                  onClick={() => toggleSelection(filters.sectors, sector, 'sectors')}
                  className={`text-xs px-3 py-1.5 rounded-full border transition-colors ${
                    filters.sectors.includes(sector)
                      ? 'bg-blue-600 text-white border-blue-600'
                      : 'bg-slate-900 text-slate-400 border-slate-700 hover:border-slate-500'
                  }`}
                >
                  {sector}
                </button>
              ))}
            </div>
          </div>
        )}

        <div className="pt-2">
            <button 
                onClick={onClose}
                className="w-full bg-slate-700 hover:bg-slate-600 text-white py-2 rounded-lg text-sm font-medium"
            >
                Show {resultCount} Results
            </button>
        </div>

      </div>
    </div>
  );
};

export default FilterPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { fetchNews } from './services/newsService';
import { analyzeArticle } from './services/geminiService';
import { addToWatchlist, getWatchlist, removeFromWatchlist } from './services/storageService';
import { AnalyzedNewsItem, ViewState, FilterState, ImpactLevel } from './types';
import { STOCK_SUGGESTIONS } from './constants';
import NewsCard from './components/NewsCard';
import FilterPanel from './components/FilterPanel';
import { IconHome, IconList, IconPlus, IconSparkles, IconTrash, IconFilter } from './components/Icons';

const App = () => {
  const [activeView, setActiveView] = useState<ViewState>('feed');
  const [news, setNews] = useState<AnalyzedNewsItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<string[]>([]);
  const [newStockInput, setNewStockInput] = useState('');

  // Filtering State
  const [showFilterPanel, setShowFilterPanel] = useState(false);
  const [filters, setFilters] = useState<FilterState>({
    sources: [],
    sectors: [],
    impactLevels: [],
    sentiments: []
  });

  // Load initial data
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      const savedWatchlist = getWatchlist();
      setWatchlist(savedWatchlist);

      const items = await fetchNews();

      // Initialize news state with "isAnalyzing" false
      const initialNews: AnalyzedNewsItem[] = items.map(item => ({
        ...item,
        isAnalyzing: false
      }));

      setNews(initialNews);
      setLoading(false);

      // Auto-analyze top 2 items to populate dashboard
      if (initialNews.length > 0) {
        // We use a small timeout to let the UI render first
        setTimeout(() => {
           handleAnalyze(initialNews[0].id, savedWatchlist, initialNews);
        }, 500);
         setTimeout(() => {
           if(initialNews[1]) handleAnalyze(initialNews[1].id, savedWatchlist, initialNews);
        }, 2000);
      }
    };
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleAnalyze = async (id: string, currentWatchlist: string[], currentNewsState = news) => {
    const itemIndex = currentNewsState.findIndex(n => n.id === id);
    if (itemIndex === -1) return;

    // Prevent double analysis
    if (currentNewsState[itemIndex].analysis || currentNewsState[itemIndex].isAnalyzing) return;

    // Set analyzing state
    setNews(prev => prev.map(n => n.id === id ? { ...n, isAnalyzing: true, analysisError: false } : n));

    try {
      const item = currentNewsState[itemIndex];
      const analysis = await analyzeArticle(item.title, item.contentSnippet, currentWatchlist);

      setNews(prev => prev.map(n => n.id === id ? { ...n, isAnalyzing: false, analysis: analysis } : n));
    } catch (e) {
      setNews(prev => prev.map(n => n.id === id ? { ...n, isAnalyzing: false, analysisError: true } : n));
    }
  };

  const handleAddToWatchlist = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!newStockInput.trim()) return;
    const updated = addToWatchlist(newStockInput.trim().toUpperCase());
    setWatchlist(updated);
    setNewStockInput('');
  };

  const handleRemoveFromWatchlist = (stock: string) => {
    const updated = removeFromWatchlist(stock);
    setWatchlist(updated);
  };

  // --- Derived Data for Filtering ---

  const availableSources = useMemo(() => {
    const sources = new Set(news.map(n => n.source));
    return Array.from(sources).sort();
  }, [news]);

  const availableSectors = useMemo(() => {
    const sectors = new Set<string>();
    news.forEach(n => {
      n.analysis?.sectors.forEach(s => sectors.add(s));
    });
    return Array.from(sectors).sort();
  }, [news]);

  const filteredNews = useMemo(() => {
    return news.filter(item => {
      // Source Filter
      if (filters.sources.length > 0 && !filters.sources.includes(item.source)) {
        return false;
      }

      // Analysis-based filters (Impact, Sentiment, Sector)
      // If any of these are active, we must have an analysis.
      // If no analysis exists, we hide the item only if these specific filters are active.
      const hasAnalysisFilters = filters.impactLevels.length > 0 || filters.sentiments.length > 0 || filters.sectors.length > 0;

      if (hasAnalysisFilters && !item.analysis) {
        return false; // Hide unanalyzed items when deep filtering
      }

      if (item.analysis) {
        if (filters.impactLevels.length > 0 && !filters.impactLevels.includes(item.analysis.impact.level)) {
            return false;
        }
        if (filters.sentiments.length > 0 && !filters.sentiments.includes(item.analysis.impact.direction)) {
            return false;
        }
        if (filters.sectors.length > 0) {
            const hasSector = item.analysis.sectors.some(s => filters.sectors.includes(s));
            if (!hasSector) return false;
        }
      }

      return true;
    });
  }, [news, filters]);

  // --- Most Impactful News Logic ---
  const mostImpactfulNews = useMemo(() => {
    // 1. Filter for items with analysis
    const analyzed = news.filter(n => n.analysis);

    // 2. Sort by Impact Score (High=3, Med=2, Low=1) + Confidence
    // Assign Base Score: High=300, Med=200, Low=100
    // Total = Base + Confidence
    const getScore = (n: AnalyzedNewsItem) => {
        if (!n.analysis) return 0;
        let base = 0;
        if (n.analysis.impact.level === ImpactLevel.HIGH) base = 300;
        else if (n.analysis.impact.level === ImpactLevel.MEDIUM) base = 200;
        else base = 100;
        return base + n.analysis.impact.confidence;
    };

    return [...analyzed]
        .sort((a, b) => getScore(b) - getScore(a))
        .slice(0, 3); // Top 3
  }, [news]);

  // Filter Watchlist view separately (can also apply source filters here if we want, but usually watchlist is specific)
  // For consistency, let's just apply the watchlist match logic to the `news` array, 
  // but maybe we should respect the filters too? 
  // User Requirement: "filter the main news feed". It doesn't explicitly say watchlist view.
  // I'll keep Watchlist view pure to the watchlist logic, but maybe respect Source filter if active?
  // Let's keep it simple: Watchlist View ignores advanced filters for now to ensure users see their stock news.
  const watchlistNews = news.filter(n => {
    if (n.analysis?.watchlistRelevance?.isRelevant) return true;
    const textToCheck = (n.title + ' ' + n.contentSnippet).toLowerCase();
    return watchlist.some(stock => textToCheck.includes(stock.toLowerCase()));
  });

  const activeFilterCount = 
    filters.sources.length + 
    filters.sectors.length + 
    filters.impactLevels.length + 
    filters.sentiments.length;

  return (
    <div className="min-h-screen bg-background text-slate-100 pb-20">

      {/* Top Bar */}
      <div className="sticky top-0 z-20 bg-background/80 backdrop-blur-md border-b border-slate-800 p-4">
        <div className="flex justify-between items-center">
            <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-gradient-to-tr from-blue-600 to-purple-600 flex items-center justify-center">
                <IconSparkles className="text-white w-5 h-5" />
            </div>
            <h1 className="font-bold text-lg tracking-tight">FinIntel<span className="text-primary font-light">India</span></h1>
            </div>
            <div className="flex items-center gap-3">
                 {/* Filter Toggle */}
                 <button 
                    onClick={() => setShowFilterPanel(!showFilterPanel)}
                    className={`relative p-2 rounded-lg transition-colors ${showFilterPanel || activeFilterCount > 0 ? 'bg-slate-700 text-white' : 'text-slate-400 hover:text-white'}`}
                >
                    <IconFilter className="w-5 h-5" />
                    {activeFilterCount > 0 && (
                        <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-primary rounded-full border border-slate-900"></span>
                    )}
                 </button>
            </div>
        </div>
        {/* Filter Panel (Collapsible) */}
        {showFilterPanel && (
            <div className="mt-4">
                <FilterPanel 
                    filters={filters}
                    setFilters={setFilters}
                    availableSources={availableSources}
                    availableSectors={availableSectors}
                    onClose={() => setShowFilterPanel(false)}
                    resultCount={filteredNews.length}
                />
            </div>
        )}
      </div>

      {/* Main Content */}
      <main className="p-4 max-w-lg mx-auto w-full">

        {loading ? (
          <div className="flex flex-col items-center justify-center mt-20 space-y-4">
             <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
             <p className="text-slate-400 text-sm">Fetching markets data...</p>
          </div>
        ) : (
          <>
            {/* FEED VIEW */}
            {activeView === 'feed' && (
              <div className="space-y-6 animate-fadeIn">

                 {/* Most Impactful Section (Only show if we have candidates and no deep filters obscuring everything) */}
                 {mostImpactfulNews.length > 0 && !showFilterPanel && (
                    <div className="bg-gradient-to-br from-slate-800 to-slate-900 border border-slate-700 rounded-xl p-4 shadow-lg relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-1 h-full bg-gradient-to-b from-yellow-400 to-orange-500"></div>
                        <h2 className="text-sm font-bold text-slate-200 uppercase tracking-wider mb-3 flex items-center gap-2">
                             <span className="text-yellow-400">⚡</span> Top Market Movers
                        </h2>
                        <div className="space-y-3">
                            {mostImpactfulNews.map(item => (
                                <div key={item.id} className="pb-3 border-b border-slate-700/50 last:border-0 last:pb-0 cursor-pointer" onClick={() => {
                                    // Scroll to item or just expand. Since we duplicate, maybe just a mini view here.
                                    // For MVP, standard view in a compact list.
                                }}>
                                    <div className="flex justify-between items-start">
                                        <h3 className="text-sm font-medium text-slate-100 line-clamp-1">{item.title}</h3>
                                        <span className={`text-[10px] px-1.5 py-0.5 rounded ml-2 whitespace-nowrap ${
                                            item.analysis?.impact.direction === 'Bullish' ? 'text-green-400 bg-green-400/10' : 
                                            item.analysis?.impact.direction === 'Bearish' ? 'text-red-400 bg-red-400/10' : 'text-slate-400 bg-slate-700'
                                        }`}>
                                            {item.analysis?.impact.level} Impact
                                        </span>
                                    </div>
                                    <p className="text-xs text-slate-400 mt-1 line-clamp-2">{item.analysis?.whyItMatters}</p>
                                </div>
                            ))}
                        </div>
                    </div>
                 )}

                 {/* Main List */}
                 <div>
                    <div className="flex items-center justify-between mb-2">
                        <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
                            {activeFilterCount > 0 ? 'Filtered News' : 'Latest Headlines'}
                        </h2>
                        <span className="text-xs text-slate-600">{filteredNews.length} articles</span>
                    </div>

                    {filteredNews.length === 0 && (
                        <div className="text-center py-12 border border-dashed border-slate-800 rounded-xl">
                            <p className="text-slate-500">No articles match your filters.</p>
                            <button onClick={() => setFilters({sources:[], sectors:[], impactLevels:[], sentiments:[]})} className="text-primary text-sm mt-2 hover:underline">Clear Filters</button>
                        </div>
                    )}

                    {filteredNews.map(item => (
                    <NewsCard 
                        key={item.id} 
                        item={item} 
                        onAnalyze={(id) => handleAnalyze(id, watchlist)} 
                    />
                    ))}
                 </div>
              </div>
            )}

            {/* WATCHLIST VIEW */}
            {activeView === 'watchlist' && (
              <div className="animate-fadeIn">
                <div className="mb-6 bg-surface p-4 rounded-xl border border-slate-700">
                  <h2 className="text-lg font-semibold mb-4">My Watchlist</h2>

                  {/* Add Stock */}
                  <form onSubmit={handleAddToWatchlist} className="flex gap-2 mb-4">
                    <input 
                      type="text" 
                      value={newStockInput}
                      onChange={(e) => setNewStockInput(e.target.value)}
                      placeholder="e.g. RELIANCE, TCS" 
                      className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-sm focus:outline-none focus:border-primary text-white placeholder-slate-500"
                    />
                    <button type="submit" className="bg-primary hover:bg-blue-600 text-white p-2 rounded-lg transition-colors">
                      <IconPlus />
                    </button>
                  </form>

                  {/* Chips */}
                  <div className="flex flex-wrap gap-2">
                    {watchlist.length === 0 && <span className="text-slate-500 text-sm italic">No stocks added yet.</span>}
                    {watchlist.map(stock => (
