import { AnalyzedNewsItem } from '../types';

const WATCHLIST_KEY = 'finintel_watchlist_v1';
const NEWS_CACHE_KEY = 'finintel_news_cache_v1';
const SIX_DAYS_MS = 6 * 24 * 60 * 60 * 1000;

// --- Watchlist ---

export const getWatchlist = (): string[] => {
  try {
    const stored = localStorage.getItem(WATCHLIST_KEY);
    return stored ? JSON.parse(stored) : [];
  } catch (e) {
    return [];
  }
};

export const addToWatchlist = (stock: string): string[] => {
  const current = getWatchlist();
  if (!current.includes(stock)) {
    const updated = [...current, stock];
    localStorage.setItem(WATCHLIST_KEY, JSON.stringify(updated));
    return updated;
  }
  return current;
};

export const removeFromWatchlist = (stock: string): string[] => {
  const current = getWatchlist();
  const updated = current.filter(s => s !== stock);
  localStorage.setItem(WATCHLIST_KEY, JSON.stringify(updated));
  return updated;
};

// --- News Cache ---

export const getNewsCache = (): AnalyzedNewsItem[] => {
  try {
    const stored = localStorage.getItem(NEWS_CACHE_KEY);
    if (!stored) return [];

    const parsed = JSON.parse(stored);
    const now = new Date().getTime();

    // Filter out items older than 6 days and re-hydrate Date objects
    return parsed
      .map((n: any) => ({
        ...n,
        isoDate: new Date(n.pubDate) // Reconstruct Date object from string
      }))
      .filter((n: AnalyzedNewsItem) => (now - n.isoDate.getTime()) < SIX_DAYS_MS);
  } catch (e) {
    console.error("Error reading news cache", e);
    return [];
  }
};

export const saveNewsCache = (news: AnalyzedNewsItem[]) => {
  try {
    const now = new Date().getTime();
    // Double check expiration before saving to keep storage clean
    const validNews = news.filter(item => {
      const itemTime = new Date(item.pubDate).getTime();
      return (now - itemTime) < SIX_DAYS_MS;
    });

    localStorage.setItem(NEWS_CACHE_KEY, JSON.stringify(validNews));
  } catch (e) {
    console.error("Error saving news cache (likely full)", e);
  }
};

import { NewsItem } from '../types';
import { RSS_FEEDS } from '../constants';

// Using corsproxy.io as it handles raw XML responses better than allorigins for some feeds
// and is less prone to "Failed to fetch" opaque errors in this context.
const PROXY_URL = 'https://corsproxy.io/?';

export const fetchNews = async (): Promise<NewsItem[]> => {
  let allNews: NewsItem[] = [];

  const fetchFeed = async (feedUrl: string, sourceName: string) => {
    try {
      // Direct fetch via CORS proxy
      const response = await fetch(`${PROXY_URL}${encodeURIComponent(feedUrl)}`);

      if (!response.ok) throw new Error(`Status: ${response.status}`);

      const text = await response.text();

      const parser = new DOMParser();
      const xml = parser.parseFromString(text, 'text/xml');
      const items = xml.querySelectorAll('item');

      const feedItems: NewsItem[] = [];

      items.forEach((item) => {
        const title = item.querySelector('title')?.textContent || '';
        const link = item.querySelector('link')?.textContent || '';
        const pubDateStr = item.querySelector('pubDate')?.textContent || '';
        const description = item.querySelector('description')?.textContent || '';

        // Basic cleanup of description (remove HTML tags often found in RSS)
        const cleanDesc = description.replace(/<[^>]*>?/gm, '').slice(0, 200) + '...';

        if (title && link) {
          // Robust Date Parsing
          let isoDate = new Date();
          if (pubDateStr) {
            isoDate = new Date(pubDateStr);
          }

          feedItems.push({
            id: btoa(link), // Simple ID generation
            title,
            link,
            pubDate: pubDateStr,
            source: sourceName,
            contentSnippet: cleanDesc,
            isoDate: isoDate
          });
        }
      });
      return feedItems;
    } catch (error) {
      console.error(`Error fetching feed ${sourceName}:`, error);
      return [];
    }
  };

  const promises = RSS_FEEDS.map(feed => fetchFeed(feed.url, feed.name));
  const results = await Promise.all(promises);

  results.forEach(feedItems => {
    allNews = [...allNews, ...feedItems];
  });

  // Sort by date descending
  return allNews.sort((a, b) => b.isoDate.getTime() - a.isoDate.getTime());
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { fetchNews } from './services/newsService';
import { analyzeArticle } from './services/geminiService';
import { addToWatchlist, getWatchlist, removeFromWatchlist, getNewsCache, saveNewsCache } from './services/storageService';
import { AnalyzedNewsItem, ViewState, FilterState, ImpactLevel } from './types';
import { STOCK_SUGGESTIONS, MASTER_STOCK_LIST } from './constants';
import NewsCard from './components/NewsCard';
import FilterPanel from './components/FilterPanel';
import { IconHome, IconList, IconPlus, IconSparkles, IconTrash, IconFilter } from './components/Icons';

const App = () => {
  const [activeView, setActiveView] = useState<ViewState>('feed');
  const [news, setNews] = useState<AnalyzedNewsItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<string[]>([]);
  const [newStockInput, setNewStockInput] = useState('');

  // Filtering State
  const [showFilterPanel, setShowFilterPanel] = useState(false);
  const [filters, setFilters] = useState<FilterState>({
    sources: [],
    sectors: [],
    impactLevels: [],
    sentiments: []
  });

  // Use refs to access latest state inside intervals without re-triggering effects
  const newsRef = useRef<AnalyzedNewsItem[]>([]);

  useEffect(() => {
      newsRef.current = news;
  }, [news]);

  // Initial Load & Polling Logic
  useEffect(() => {
    const initialize = async () => {
        // 1. Load Watchlist
        const savedWatchlist = getWatchlist();
        setWatchlist(savedWatchlist);

        // 2. Load Cached News (Fast Render)
        const cachedNews = getNewsCache();
        if (cachedNews.length > 0) {
            setNews(cachedNews);
            setLoading(false);
        }

        // 3. Initial Fetch
        await fetchAndMergeNews();
        setLoading(false);
    };

    initialize();

    // 4. Set up 30-second polling
    const intervalId = setInterval(() => {
        fetchAndMergeNews();
    }, 30000); // 30 seconds

    return () => clearInterval(intervalId);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once on mount

  const fetchAndMergeNews = async () => {
    try {
        const freshItems = await fetchNews();
        const currentNews = newsRef.current;
        const currentIds = new Set(currentNews.map(n => n.id));

        // Identify truly new items
        const newItems = freshItems.filter(item => !currentIds.has(item.id));

        if (newItems.length === 0) {
            // No new news, just clean up old stuff
            const cleaned = cleanOldNews(currentNews);
            if (cleaned.length !== currentNews.length) {
                setNews(cleaned);
                saveNewsCache(cleaned);
            }
            return;
        }

        // Merge: New items + Existing items (preserving analysis)
        // Add isAnalyzing: false to new items
        const newAnalyzedItems: AnalyzedNewsItem[] = newItems.map(item => ({
            ...item,
            isAnalyzing: false
        }));

        let merged = [...newAnalyzedItems, ...currentNews];

        // Clean up items older than 6 days
        merged = cleanOldNews(merged);

        // Sort by date
        merged.sort((a, b) => b.isoDate.getTime() - a.isoDate.getTime());

        setNews(merged);
        saveNewsCache(merged);

        // Optional: Auto-analyze top new item if it's very fresh? 
        // For MVP, we let user initiate or rely on manual clicks to save tokens.

    } catch (e) {
        console.error("Polling error", e);
    }
  };

  const cleanOldNews = (items: AnalyzedNewsItem[]) => {
      const now = new Date().getTime();
      const SIX_DAYS_MS = 6 * 24 * 60 * 60 * 1000;
      return items.filter(n => (now - n.isoDate.getTime()) < SIX_DAYS_MS);
  };

  const handleAnalyze = async (id: string, currentWatchlist: string[], currentNewsState = news) => {
    const itemIndex = currentNewsState.findIndex(n => n.id === id);
    if (itemIndex === -1) return;

    // Prevent double analysis
    if (currentNewsState[itemIndex].analysis || currentNewsState[itemIndex].isAnalyzing) return;

    // Set analyzing state
    const updatedWithLoading = currentNewsState.map(n => n.id === id ? { ...n, isAnalyzing: true, analysisError: false } : n);
    setNews(updatedWithLoading);

    try {
      const item = currentNewsState[itemIndex];
      const analysis = await analyzeArticle(item.title, item.contentSnippet, currentWatchlist);

      const finalState = updatedWithLoading.map(n => n.id === id ? { ...n, isAnalyzing: false, analysis: analysis } : n);
      setNews(finalState);
      saveNewsCache(finalState); // Save analysis result
    } catch (e) {
      setNews(prev => prev.map(n => n.id === id ? { ...n, isAnalyzing: false, analysisError: true } : n));
    }
  };

  const handleAddToWatchlist = (e?: React.FormEvent, stockName?: string) => {
    e?.preventDefault();
    const stockToAdd = stockName || newStockInput;
    if (!stockToAdd.trim()) return;
    const formattedStock = stockToAdd.trim().toUpperCase();
    const updated = addToWatchlist(formattedStock);
    setWatchlist(updated);
    setNewStockInput('');
  };

  const handleRemoveFromWatchlist = (stock: string) => {
    const updated = removeFromWatchlist(stock);
    setWatchlist(updated);
  };

  // --- Derived Data for Filtering ---

  const availableSources = useMemo(() => {
    const sources = new Set(news.map(n => n.source));
    return Array.from(sources).sort();
  }, [news]);

  const availableSectors = useMemo(() => {
    const sectors = new Set<string>();
    news.forEach(n => {
      n.analysis?.sectors.forEach(s => sectors.add(s));
    });
    return Array.from(sectors).sort();
  }, [news]);

  const filteredNews = useMemo(() => {
    return news.filter(item => {
      if (filters.sources.length > 0 && !filters.sources.includes(item.source)) return false;

      const hasAnalysisFilters = filters.impactLevels.length > 0 || filters.sentiments.length > 0 || filters.sectors.length > 0;
      if (hasAnalysisFilters && !item.analysis) return false;

      if (item.analysis) {
        if (filters.impactLevels.length > 0 && !filters.impactLevels.includes(item.analysis.impact.level)) return false;
        if (filters.sentiments.length > 0 && !filters.sentiments.includes(item.analysis.impact.direction)) return false;
        if (filters.sectors.length > 0) {
            const hasSector = item.analysis.sectors.some(s => filters.sectors.includes(s));
            if (!hasSector) return false;
        }
      }
      return true;
    });
  }, [news, filters]);

  const mostImpactfulNews = useMemo(() => {
    const analyzed = news.filter(n => n.analysis);
    const getScore = (n: AnalyzedNewsItem) => {
        if (!n.analysis) return 0;
        let base = 0;
        if (n.analysis.impact.level === ImpactLevel.HIGH) base = 300;
        else if (n.analysis.impact.level === ImpactLevel.MEDIUM) base = 200;
        else base = 100;
        return base + n.analysis.impact.confidence;
    };
    return [...analyzed].sort((a, b) => getScore(b) - getScore(a)).slice(0, 3);
  }, [news]);

  const autocompleteSuggestions = useMemo(() => {
    if (!newStockInput.trim()) return [];
    const search = newStockInput.toLowerCase();
    return MASTER_STOCK_LIST.filter(stock => 
      stock.toLowerCase().includes(search) && !watchlist.includes(stock.toUpperCase())
    ).slice(0, 5);
  }, [newStockInput, watchlist]);

  // Watchlist news filter (uses raw news data + watchlist, not affected by main feed filters)
  const watchlistNews = useMemo(() => {
      return news.filter(n => {
        if (n.analysis?.watchlistRelevance?.isRelevant) return true;
        const textToCheck = (n.title + ' ' + n.contentSnippet).toLowerCase();
        return watchlist.some(stock => textToCheck.includes(stock.toLowerCase()));
      });
  }, [news, watchlist]);

  const activeFilterCount = filters.sources.length + filters.sectors.length + filters.impactLevels.length + filters.sentiments.length;

  return (
    <div className="min-h-screen bg-background text-slate-100 pb-20">

      {/* Top Bar */}
      <div className="sticky top-0 z-20 bg-background/80 backdrop-blur-md border-b border-slate-800 p-4">
        <div className="flex justify-between items-center">
            <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-gradient-to-tr from-blue-600 to-purple-600 flex items-center justify-center">
                <IconSparkles className="text-white w-5 h-5" />
            </div>
            <h1 className="font-bold text-lg tracking-tight">FinIntel<span className="text-primary font-light">India</span></h1>
            </div>
            <div className="flex items-center gap-3">
                 <button 
                    onClick={() => setShowFilterPanel(!showFilterPanel)}
                    className={`relative p-2 rounded-lg transition-colors ${showFilterPanel || activeFilterCount > 0 ? 'bg-slate-700 text-white' : 'text-slate-400 hover:text-white'}`}
                >
                    <IconFilter className="w-5 h-5" />
                    {activeFilterCount > 0 && (
                        <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-primary rounded-full border border-slate-900"></span>
                    )}
                 </button>
            </div>
        </div>
        {showFilterPanel && (
            <div className="mt-4">
                <FilterPanel 
                    filters={filters}
                    setFilters={setFilters}
                    availableSources={availableSources}
                    availableSectors={availableSectors}
                    onClose={() => setShowFilterPanel(false)}
                    resultCount={filteredNews.length}
                />
            </div>
        )}
      </div>

      {/* Main Content */}
      <main className="p-4 max-w-lg mx-auto w-full">

        {loading && news.length === 0 ? (
          <div className="flex flex-col items-center justify-center mt-20 space-y-4">
             <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
             <p className="text-slate-400 text-sm">Fetching markets data...</p>
          </div>
        ) : (
          <>
            {/* Using display:none for view switching to prevent remounting/flashing */}

            {/* FEED VIEW */}
            <div style={{ display: activeView === 'feed' ? 'block' : 'none' }} className="space-y-6 animate-fadeIn">

                 {mostImpactfulNews.length > 0 && !showFilterPanel && (
                    <div className="bg-gradient-to-br from-slate-800 to-slate-900 border border-slate-700 rounded-xl p-4 shadow-lg relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-1 h-full bg-gradient-to-b from-yellow-400 to-orange-500"></div>
                        <h2 className="text-sm font-bold text-slate-200 uppercase tracking-wider mb-3 flex items-center gap-2">
                             <span className="text-yellow-400">⚡</span> Top Market Movers
                        </h2>
                        <div className="space-y-3">
                            {mostImpactfulNews.map(item => (
                                <div key={item.id} className="pb-3 border-b border-slate-700/50 last:border-0 last:pb-0 cursor-pointer">
                                    <div className="flex justify-between items-start">
                                        <h3 className="text-sm font-medium text-slate-100 line-clamp-1">{item.title}</h3>
                                        <span className={`text-[10px] px-1.5 py-0.5 rounded ml-2 whitespace-nowrap ${
                                            item.analysis?.impact.direction === 'Bullish' ? 'text-green-400 bg-green-400/10' : 
                                            item.analysis?.impact.direction === 'Bearish' ? 'text-red-400 bg-red-400/10' : 'text-slate-400 bg-slate-700'
                                        }`}>
                                            {item.analysis?.impact.level} Impact
                                        </span>
                                    </div>
                                    <p className="text-xs text-slate-400 mt-1 line-clamp-2">{item.analysis?.whyItMatters}</p>
                                </div>
                            ))}
                        </div>
                    </div>
                 )}

                 <div>
                    <div className="flex items-center justify-between mb-2">
                        <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
                            {activeFilterCount > 0 ? 'Filtered News' : 'Latest Headlines'}
                        </h2>
                        <span className="text-xs text-slate-600">{filteredNews.length} articles</span>
                    </div>

                    {filteredNews.length === 0 && (
                        <div className="text-center py-12 border border-dashed border-slate-800 rounded-xl">
                            <p className="text-slate-500">No articles match your filters.</p>
                            <button onClick={() => setFilters({sources:[], sectors:[], impactLevels:[], sentiments:[]})} className="text-primary text-sm mt-2 hover:underline">Clear Filters</button>
                        </div>
                    )}

                    {filteredNews.map(item => (
                    <NewsCard 
                        key={item.id} 
                        item={item} 
                        onAnalyze={(id) => handleAnalyze(id, watchlist)} 
                    />
                    ))}
                 </div>
            </div>

            {/* WATCHLIST VIEW */}
            <div style={{ display: activeView === 'watchlist' ? 'block' : 'none' }} className="animate-fadeIn">
                <div className="mb-6 bg-surface p-4 rounded-xl border border-slate-700">
                  <h2 className="text-lg font-semibold mb-4">My Watchlist</h2>

                  <div className="relative mb-4">
                      <form onSubmit={(e) => handleAddToWatchlist(e)} className="flex gap-2">
                        <input 
                          type="text" 
                          value={newStockInput}
                          onChange={(e) => setNewStockInput(e.target.value)}
                          placeholder="e.g. RELIANCE, TCS" 
                          className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-sm focus:outline-none focus:border-primary text-white placeholder-slate-500"
                        />
                        <button type="submit" className="bg-primary hover:bg-blue-600 text-white p-2 rounded-lg transition-colors">
                          <IconPlus />
                        </button>
                      </form>

                      {autocompleteSuggestions.length > 0 && (
                          <div className="absolute top-full left-0 right-0 mt-1 bg-slate-800 border border-slate-700 rounded-lg shadow-xl z-30 max-h-48 overflow-y-auto">
                              {autocompleteSuggestions.map((suggestion) => (
                                  <button
                                      key={suggestion}
                                      onClick={() => handleAddToWatchlist(undefined, suggestion)}
                                      className="w-full text-left px-4 py-2 text-sm text-slate-300 hover:bg-slate-700 hover:text-white border-b border-slate-700/50 last:border-0"
                                  >
                                      {suggestion}
                                  </button>
                              ))}
                          </div>
                      )}
                  </div>

                  <div className="flex flex-wrap gap-2">
                    {watchlist.length === 0 && <span className="text-slate-500 text-sm italic">No stocks added yet.</span>}
                    {watchlist.map(stock => (
                      <div key={stock} className="flex items-center gap-1 bg-slate-800 border border-slate-600 text-xs px-3 py-1.5 rounded-full">
                        <span className="font-medium text-slate-200">{stock}</span>
                        <button onClick={() => handleRemoveFromWatchlist(stock)} className="text-slate-400 hover:text-red-400">
                           <IconTrash className="w-3 h-3" />
                        </button>
                      </div>
                    ))}
                  </div>

                  {watchlist.length < 3 && newStockInput.length === 0 && (
                     <div className="mt-4 pt-4 border-t border-slate-700/50">
                        <p className="text-xs text-slate-500 mb-2">Popular Picks:</p>
                        <div className="flex flex-wrap gap-2">
                           {STOCK_SUGGESTIONS.slice(0, 5).filter(s => !watchlist.includes(s.toUpperCase())).map(s => (
                              <button 
                                key={s} 
                                onClick={() => {
                                   const updated = addToWatchlist(s.toUpperCase());
                                   setWatchlist(updated);
                                }}
                                className="text-[10px] bg-slate-900 text-slate-400 border border-slate-800 px-2 py-1 rounded hover:border-slate-600"
                              >
                                + {s}
                              </button>
                           ))}
                        </div>
                     </div>
                  )}
                </div>

                <div className="flex items-center justify-between mb-2">
                    <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Watchlist News</h2>
                 </div>

                 {watchlistNews.length > 0 ? (
                    watchlistNews.map(item => (
                      <NewsCard 
                          key={item.id} 
                          item={item} 
                          onAnalyze={(id) => handleAnalyze(id, watchlist)} 
                       />
                    ))
                 ) : (
                   <div className="text-center py-10 text-slate-500">
                      <p>No recent news matched your watchlist.</p>
                      <p className="text-xs mt-1">Try adding broader terms like "BANK" or "AUTO".</p>
                   </div>
                 )}
            </div>
          </>
        )}
      </main>

      {/* Bottom Nav */}
      <nav className="fixed bottom-0 left-0 w-full bg-background/90 backdrop-blur-lg border-t border-slate-800 pb-safe">
        <div className="flex justify-around items-center p-2 max-w-lg mx-auto">
          <button 
            onClick={() => setActiveView('feed')}
            className={`flex flex-col items-center p-2 rounded-lg w-16 transition-all ${activeView === 'feed' ? 'text-primary' : 'text-slate-500'}`}
          >
            <IconHome className={activeView === 'feed' ? 'stroke-[2.5px]' : ''} />
            <span className="text-[10px] mt-1 font-medium">Feed</span>
          </button>

          <button 
            onClick={() => setActiveView('watchlist')}
            className={`flex flex-col items-center p-2 rounded-lg w-16 transition-all ${activeView === 'watchlist' ? 'text-primary' : 'text-slate-500'}`}
          >
            <IconList className={activeView === 'watchlist' ? 'stroke-[2.5px]' : ''} />
            <span className="text-[10px] mt-1 font-medium">Watchlist</span>
          </button>
        </div>
      </nav>

      <style>{`
        .pb-safe { padding-bottom: env(safe-area-inset-bottom, 20px); }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fadeIn { animation: fadeIn 0.4s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

