import { AnalyzedNewsItem } from '../types';

const WATCHLIST_KEY = 'finintel_watchlist_v1';
const NEWS_CACHE_KEY = 'finintel_news_cache_v3'; // Incremented to v3 for Detailed Briefing
const SIX_DAYS_MS = 6 * 24 * 60 * 60 * 1000;

// --- Watchlist ---

export const getWatchlist = (): string[] => {
  try {
    const stored = localStorage.getItem(WATCHLIST_KEY);
    return stored ? JSON.parse(stored) : [];
  } catch (e) {
    return [];
  }
};

export const addToWatchlist = (stock: string): string[] => {
  const current = getWatchlist();
  if (!current.includes(stock)) {
    const updated = [...current, stock];
    localStorage.setItem(WATCHLIST_KEY, JSON.stringify(updated));
    return updated;
  }
  return current;
};

export const removeFromWatchlist = (stock: string): string[] => {
  const current = getWatchlist();
  const updated = current.filter(s => s !== stock);
  localStorage.setItem(WATCHLIST_KEY, JSON.stringify(updated));
  return updated;
};

// --- News Cache ---

export const getNewsCache = (): AnalyzedNewsItem[] => {
  try {
    const stored = localStorage.getItem(NEWS_CACHE_KEY);
    if (!stored) return [];

    const parsed = JSON.parse(stored);
    const now = new Date().getTime();

    // Filter out items older than 6 days and re-hydrate Date objects
    return parsed
      .map((n: any) => ({
        ...n,
        isoDate: new Date(n.pubDate) // Reconstruct Date object from string
      }))
      .filter((n: AnalyzedNewsItem) => (now - n.isoDate.getTime()) < SIX_DAYS_MS);
  } catch (e) {
    console.error("Error reading news cache", e);
    return [];
  }
};

export const saveNewsCache = (news: AnalyzedNewsItem[]) => {
  try {
    const now = new Date().getTime();
    // Double check expiration before saving to keep storage clean
    const validNews = news.filter(item => {
      const itemTime = new Date(item.pubDate).getTime();
      return (now - itemTime) < SIX_DAYS_MS;
    });

    localStorage.setItem(NEWS_CACHE_KEY, JSON.stringify(validNews));
  } catch (e) {
    console.error("Error saving news cache (likely full)", e);
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { AIAnalysis, ImpactDirection, ImpactLevel } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeArticle = async (
  title: string, 
  snippet: string, 
  userWatchlist: string[]
): Promise<AIAnalysis> => {

  const model = "gemini-3-flash-preview";

  const prompt = `
    Analyze this financial news article for the Indian Stock Market context.

    Article Title: "${title}"
    Snippet: "${snippet}"
    User Watchlist: ${JSON.stringify(userWatchlist)}

    Tasks:
    1. Summarize the news in 3-4 bullet lines (TL;DR).
    2. Explain "Why this matters" in 1-2 lines.
    3. Identify 3-4 relevant Indian business sectors.
    4. Identify potentially affected Indian stock tickers/company names (NSE/BSE).
    5. Determine market sentiment (Bullish/Bearish/Neutral) and impact level.
    6. Check if it affects any stock in the User Watchlist.
    7. **Ripple Effect (Second-Order Thinking):** Map the chain reaction. Event -> Intermediate Consequence -> Final Stock Impact.
    8. **B.S. Detector (Credibility):** Rate reliability 0-100 based on source authority and language (Fact vs Opinion).
    9. **Detailed Briefing:** Write a comprehensive, professional 2-paragraph briefing of this news event suitable for an investor.

    Return JSON only.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            detailedSummary: { type: Type.STRING, description: "A detailed 2-paragraph investor briefing" },
            whyItMatters: { type: Type.STRING },
            sectors: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            relatedStocks: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            impact: {
              type: Type.OBJECT,
              properties: {
                direction: { type: Type.STRING, enum: [ImpactDirection.BULLISH, ImpactDirection.BEARISH, ImpactDirection.NEUTRAL] },
                level: { type: Type.STRING, enum: [ImpactLevel.LOW, ImpactLevel.MEDIUM, ImpactLevel.HIGH] },
                confidence: { type: Type.NUMBER }
              }
            },
            watchlistRelevance: {
              type: Type.OBJECT,
              properties: {
                isRelevant: { type: Type.BOOLEAN },
                reason: { type: Type.STRING }
              }
            },
            rippleEffect: {
              type: Type.OBJECT,
              properties: {
                trigger: { type: Type.STRING, description: "The immediate news event" },
                intermediate: { type: Type.STRING, description: "The downstream economic/sector effect" },
                finalImpact: { type: Type.STRING, description: "The resulting impact on specific companies" }
              }
            },
            credibility: {
              type: Type.OBJECT,
              properties: {
                score: { type: Type.NUMBER, description: "0-100 score" },
                verdict: { type: Type.STRING, enum: ['Verified Fact', 'Likely True', 'Speculative', 'Rumor/Opinion'] },
                reason: { type: Type.STRING }
              }
            }
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as AIAnalysis;
    }
    throw new Error("No text response from AI");
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

