);

export const IconArrowDown = ({ className }: { className?: string }) => (
    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}><line x1="12" y1="5" x2="12" y2="19"></line><polyline points="19 12 12 19 5 12"></polyline></svg>
);

export const IconBook = ({ className }: { className?: string }) => (
    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}><path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"></path><path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"></path></svg>
);

export const IconExternalLink = ({ className }: { className?: string }) => (
    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"></path><polyline points="15 3 21 3 21 9"></polyline><line x1="10" y1="14" x2="21" y2="3"></line></svg>
);

import React, { useState } from 'react';
import { AnalyzedNewsItem, ImpactDirection, ImpactLevel } from '../types';
import { IconTrendingUp, IconTrendingDown, IconMinus, IconSparkles, IconLayers, IconShieldCheck, IconAlertTriangle, IconArrowDown, IconBook, IconExternalLink } from './Icons';
import NewsDetailModal from './NewsDetailModal';

interface NewsCardProps {
  item: AnalyzedNewsItem;
  onAnalyze: (id: string) => void;
}

const NewsCard: React.FC<NewsCardProps> = ({ item, onAnalyze }) => {
  const { analysis, isAnalyzing, analysisError } = item;
  const [showModal, setShowModal] = useState(false);

  const getImpactColor = (direction: ImpactDirection) => {
    switch (direction) {
      case ImpactDirection.BULLISH: return 'text-bullish bg-emerald-400/10 border-emerald-400/20';
      case ImpactDirection.BEARISH: return 'text-bearish bg-red-400/10 border-red-400/20';
      default: return 'text-neutral bg-slate-400/10 border-slate-400/20';
    }
  };

  const getImpactIcon = (direction: ImpactDirection) => {
    switch (direction) {
      case ImpactDirection.BULLISH: return <IconTrendingUp className="w-4 h-4 mr-1" />;
      case ImpactDirection.BEARISH: return <IconTrendingDown className="w-4 h-4 mr-1" />;
      default: return <IconMinus className="w-4 h-4 mr-1" />;
    }
  };

  const getCredibilityStyles = (score: number) => {
      if (score >= 80) return { color: 'text-emerald-400', bg: 'bg-emerald-400/10', border: 'border-emerald-400/20', icon: IconShieldCheck };
      if (score >= 50) return { color: 'text-yellow-400', bg: 'bg-yellow-400/10', border: 'border-yellow-400/20', icon: IconShieldCheck };
      return { color: 'text-red-400', bg: 'bg-red-400/10', border: 'border-red-400/20', icon: IconAlertTriangle };
  };

  return (
    <>
    <div className="bg-surface rounded-xl p-4 mb-4 border border-slate-700/50 shadow-sm relative overflow-hidden transition-all duration-300">
      {/* Watchlist Highlight */}
      {analysis?.watchlistRelevance?.isRelevant && (
        <div className="absolute top-0 right-0 bg-primary/20 text-primary text-[10px] font-bold px-2 py-1 rounded-bl-lg uppercase tracking-wider">
          In Watchlist
        </div>
      )}

      {/* Header */}
      <div className="flex justify-between items-start mb-2">
        <div className="flex gap-2 items-center">
            <span className="text-[10px] text-slate-400 font-medium uppercase tracking-wider bg-slate-900 px-2 py-0.5 rounded">
            {item.source}
            </span>
            {/* Credibility Badge (The B.S. Detector) */}
            {analysis?.credibility && (
                <div className={`flex items-center gap-1 text-[10px] px-1.5 py-0.5 rounded border ${getCredibilityStyles(analysis.credibility.score).bg} ${getCredibilityStyles(analysis.credibility.score).border} ${getCredibilityStyles(analysis.credibility.score).color}`}>
                    {React.createElement(getCredibilityStyles(analysis.credibility.score).icon, { className: "w-3 h-3" })}
                    <span className="font-semibold">{analysis.credibility.score}% Reliable</span>
                </div>
            )}
        </div>
        <span className="text-[10px] text-slate-500">
           {new Date(item.pubDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric', hour: '2-digit', minute:'2-digit' })}
        </span>
      </div>

      <h3 className="text-base font-semibold text-slate-100 mb-2 leading-tight">
        {item.title}
      </h3>

      {/* Analysis Section or Analyze Action */}
      {!analysis && !isAnalyzing && (
        <div className="mt-3">
          <p className="text-sm text-slate-400 mb-3 line-clamp-2">
            {item.contentSnippet}
          </p>
          <button 
            onClick={() => onAnalyze(item.id)}
            className="w-full flex items-center justify-center gap-2 bg-slate-700 hover:bg-slate-600 active:bg-slate-800 text-slate-200 text-sm font-medium py-2 rounded-lg transition-colors border border-slate-600"
          >
            <IconSparkles className="w-4 h-4 text-purple-400" />
            Analyze Impact
          </button>
          {analysisError && <p className="text-xs text-red-400 mt-2 text-center">Analysis failed. Please try again.</p>}
        </div>
      )}

      {isAnalyzing && (
        <div className="mt-3 py-4 flex flex-col items-center justify-center space-y-2 bg-slate-900/30 rounded-lg animate-pulse">
           <IconSparkles className="w-5 h-5 text-purple-400 animate-spin" />
           <span className="text-xs text-slate-400">Analyzing ripple effects...</span>
        </div>
      )}

      {analysis && (
        <div className="mt-4 animate-fadeIn">
          {/* Sentiment Badge */}
          <div className="flex flex-wrap items-center gap-2 mb-3">
            <div className={`inline-flex items-center px-2 py-1 rounded-md border text-xs font-semibold ${getImpactColor(analysis.impact.direction)}`}>
                {getImpactIcon(analysis.impact.direction)}
                {analysis.impact.direction} • {analysis.impact.level} Impact
            </div>
            {analysis.credibility.score < 50 && (
                <span className="text-[10px] text-red-400 italic">⚠️ {analysis.credibility.verdict}</span>
            )}
          </div>

          {/* Core Analysis */}
          <div className="space-y-3 text-sm">
            <div className="bg-slate-900/50 p-3 rounded-lg border border-slate-700/30">
                <p className="text-slate-300 mb-2"><span className="text-purple-400 font-semibold">TL;DR:</span> {analysis.summary}</p>
                <p className="text-slate-400 text-xs italic"><span className="text-blue-400 font-semibold">Why it matters:</span> {analysis.whyItMatters}</p>
            </div>

            {/* The Ripple Effect (Innovation #1) */}
            {analysis.rippleEffect && (
                 <div className="bg-gradient-to-br from-slate-800 to-slate-900 p-3 rounded-lg border border-slate-700 relative overflow-hidden">
                    <div className="flex items-center gap-2 mb-3">
                        <div className="p-1 bg-blue-500/20 rounded">
                            <IconLayers className="w-3.5 h-3.5 text-blue-400" />
                        </div>
                        <h4 className="text-xs font-bold text-slate-200 uppercase tracking-wide">The Ripple Effect</h4>
                    </div>

                    <div className="flex flex-col gap-0.5">
                        {/* Trigger */}
                        <div className="flex items-start gap-3">
                             <div className="flex flex-col items-center mt-1">
                                <div className="w-2 h-2 rounded-full bg-slate-500"></div>
                                <div className="w-0.5 h-6 bg-slate-700"></div>
                             </div>
                             <div className="pb-2">
                                <span className="text-[10px] text-slate-500 font-mono">EVENT</span>
                                <p className="text-xs text-slate-200">{analysis.rippleEffect.trigger}</p>
                             </div>
                        </div>

                        {/* Intermediate */}
                        <div className="flex items-start gap-3">
                             <div className="flex flex-col items-center">
                                <div className="w-2 h-2 rounded-full bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)]"></div>
                                <div className="w-0.5 h-6 bg-slate-700"></div>
                             </div>
                             <div className="pb-2">
                                <span className="text-[10px] text-blue-400 font-mono">EFFECT</span>
                                <p className="text-xs text-slate-200">{analysis.rippleEffect.intermediate}</p>
                             </div>
                        </div>

                        {/* Final */}
                        <div className="flex items-start gap-3">
                             <div className="flex flex-col items-center">
                                <IconArrowDown className="w-3 h-3 text-emerald-400" />
                             </div>
                             <div>
                                <span className="text-[10px] text-emerald-400 font-mono">IMPACT</span>
                                <p className="text-xs text-slate-200 font-medium">{analysis.rippleEffect.finalImpact}</p>
                             </div>
                        </div>
                    </div>
                 </div>
            )}

            {/* Watchlist Context */}
            {analysis.watchlistRelevance?.isRelevant && (
                <div className="bg-primary/10 p-2 rounded-lg border border-primary/20">
                    <p className="text-xs text-blue-200">
                        <span className="font-bold">⚠️ Watchlist Alert:</span> {analysis.watchlistRelevance.reason}
                    </p>
                </div>
            )}

            {/* Tags */}
            <div className="flex flex-wrap gap-1.5 mt-2">
              {analysis.relatedStocks.map(stock => (
                <span key={stock} className="text-[10px] bg-slate-700 text-slate-200 px-2 py-0.5 rounded-full border border-slate-600">
                  {stock}
                </span>
              ))}
              {analysis.sectors.map(sector => (
                 <span key={sector} className="text-[10px] bg-slate-800 text-slate-400 px-2 py-0.5 rounded-full">
                 #{sector}
               </span>
              ))}
            </div>
          </div>

          <div className="flex gap-2 mt-4">
            <button 
                onClick={() => setShowModal(true)}
                className="flex-1 flex items-center justify-center gap-1.5 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs py-2 rounded-lg transition-colors border border-slate-700"
            >
                <IconBook className="w-3.5 h-3.5" />
                Read Briefing
            </button>
            <a 
                href={item.link} 
                target="_blank" 
                rel="noopener noreferrer" 
                className="flex-1 flex items-center justify-center gap-1.5 bg-slate-800 hover:bg-slate-700 text-slate-200 text-xs py-2 rounded-lg transition-colors border border-slate-700"
            >
                <IconExternalLink className="w-3.5 h-3.5" />
                Original Source
            </a>
          </div>
        </div>
      )}
    </div>

    {showModal && (
        <NewsDetailModal 
            item={item} 
            onClose={() => setShowModal(false)} 
        />
    )}
    </>
  );
};

export default NewsCard;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { fetchNews } from './services/newsService';
import { analyzeArticle } from './services/geminiService';
import { addToWatchlist, getWatchlist, removeFromWatchlist, getNewsCache, saveNewsCache } from './services/storageService';
import { AnalyzedNewsItem, ViewState, FilterState, ImpactLevel } from './types';
import { STOCK_SUGGESTIONS, MASTER_STOCK_LIST } from './constants';
import NewsCard from './components/NewsCard';
import FilterPanel from './components/FilterPanel';
import { IconHome, IconList, IconPlus, IconSparkles, IconTrash, IconFilter, IconRefresh } from './components/Icons';

const App = () => {
  const [activeView, setActiveView] = useState<ViewState>('feed');
  const [news, setNews] = useState<AnalyzedNewsItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<string[]>([]);
  const [newStockInput, setNewStockInput] = useState('');
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [toastMessage, setToastMessage] = useState<string | null>(null);

  // Filtering State
  const [showFilterPanel, setShowFilterPanel] = useState(false);
  const [filters, setFilters] = useState<FilterState>({
    sources: [],
    sectors: [],
    impactLevels: [],
    sentiments: []
  });

  // Use refs to access latest state inside intervals without re-triggering effects
  const newsRef = useRef<AnalyzedNewsItem[]>([]);

  useEffect(() => {
      newsRef.current = news;
  }, [news]);

  // Initial Load & Polling Logic
  useEffect(() => {
    const initialize = async () => {
        // 1. Load Watchlist
        const savedWatchlist = getWatchlist();
        setWatchlist(savedWatchlist);

        // 2. Load Cached News (Fast Render)
        const cachedNews = getNewsCache();
        if (cachedNews.length > 0) {
            setNews(cachedNews);
            setLoading(false);
        }

        // 3. Initial Fetch
        await fetchAndMergeNews();
        setLoading(false);
    };

    initialize();

    // 4. Set up 30-second polling
    const intervalId = setInterval(() => {
        fetchAndMergeNews();
    }, 30000); // 30 seconds

    return () => clearInterval(intervalId);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once on mount

  const fetchAndMergeNews = async () => {
    try {
        const freshItems = await fetchNews();
        const currentNews = newsRef.current;
        const currentIds = new Set(currentNews.map(n => n.id));

        // Identify truly new items
        const newItems = freshItems.filter(item => !currentIds.has(item.id));

        if (newItems.length === 0) {
            // No new news, just clean up old stuff
            const cleaned = cleanOldNews(currentNews);
            if (cleaned.length !== currentNews.length) {
                setNews(cleaned);
                saveNewsCache(cleaned);
            }
            return;
        }

        // Merge: New items + Existing items (preserving analysis)
        // Add isAnalyzing: false to new items
        const newAnalyzedItems: AnalyzedNewsItem[] = newItems.map(item => ({
            ...item,
            isAnalyzing: false
        }));

        let merged = [...newAnalyzedItems, ...currentNews];

        // Clean up items older than 6 days
        merged = cleanOldNews(merged);

        // Sort by date
        merged.sort((a, b) => b.isoDate.getTime() - a.isoDate.getTime());

        setNews(merged);
        saveNewsCache(merged);

        // Optional: Auto-analyze top new item if it's very fresh? 
        // For MVP, we let user initiate or rely on manual clicks to save tokens.

    } catch (e) {
        console.error("Polling error", e);
    }
  };

  const handleManualRefresh = async () => {
    if (isRefreshing) return;
    setIsRefreshing(true);
    await fetchAndMergeNews();

    // Show success toast
    setToastMessage("Successfully refreshed");
    setTimeout(() => setToastMessage(null), 3000);

    // Keep spinner going a bit longer for visual feedback
    setTimeout(() => setIsRefreshing(false), 800);
  };

  const cleanOldNews = (items: AnalyzedNewsItem[]) => {
      const now = new Date().getTime();
      const SIX_DAYS_MS = 6 * 24 * 60 * 60 * 1000;
      return items.filter(n => (now - n.isoDate.getTime()) < SIX_DAYS_MS);
  };

  const handleAnalyze = async (id: string, currentWatchlist: string[], currentNewsState = news) => {
    const itemIndex = currentNewsState.findIndex(n => n.id === id);
    if (itemIndex === -1) return;

    // Prevent double analysis
    if (currentNewsState[itemIndex].analysis || currentNewsState[itemIndex].isAnalyzing) return;

    // Set analyzing state
    const updatedWithLoading = currentNewsState.map(n => n.id === id ? { ...n, isAnalyzing: true, analysisError: false } : n);
    setNews(updatedWithLoading);

    try {
      const item = currentNewsState[itemIndex];
      const analysis = await analyzeArticle(item.title, item.contentSnippet, currentWatchlist);

      const finalState = updatedWithLoading.map(n => n.id === id ? { ...n, isAnalyzing: false, analysis: analysis } : n);
      setNews(finalState);
      saveNewsCache(finalState); // Save analysis result
    } catch (e) {
      setNews(prev => prev.map(n => n.id === id ? { ...n, isAnalyzing: false, analysisError: true } : n));
    }
  };

  const handleAddToWatchlist = (e?: React.FormEvent, stockName?: string) => {
    e?.preventDefault();
    const stockToAdd = stockName || newStockInput;
    if (!stockToAdd.trim()) return;
    const formattedStock = stockToAdd.trim().toUpperCase();
    const updated = addToWatchlist(formattedStock);
    setWatchlist(updated);
    setNewStockInput('');
  };

  const handleRemoveFromWatchlist = (stock: string) => {
    const updated = removeFromWatchlist(stock);
    setWatchlist(updated);
  };

  // --- Derived Data for Filtering ---

  const availableSources = useMemo(() => {
    const sources = new Set(news.map(n => n.source));
    return Array.from(sources).sort();
  }, [news]);

  const availableSectors = useMemo(() => {
    const sectors = new Set<string>();
    news.forEach(n => {
      // Fix: Add optional chaining to prevent crash if sectors is undefined
      n.analysis?.sectors?.forEach(s => sectors.add(s));
    });
    return Array.from(sectors).sort();
  }, [news]);

  const filteredNews = useMemo(() => {
    return news.filter(item => {
      if (filters.sources.length > 0 && !filters.sources.includes(item.source)) return false;

      const hasAnalysisFilters = filters.impactLevels.length > 0 || filters.sentiments.length > 0 || filters.sectors.length > 0;
      if (hasAnalysisFilters && !item.analysis) return false;

      if (item.analysis) {
        if (filters.impactLevels.length > 0 && !filters.impactLevels.includes(item.analysis.impact.level)) return false;
        if (filters.sentiments.length > 0 && !filters.sentiments.includes(item.analysis.impact.direction)) return false;
        if (filters.sectors.length > 0) {
            // Fix: Add optional chaining for sectors array here as well
            const hasSector = item.analysis.sectors?.some(s => filters.sectors.includes(s));
            if (!hasSector) return false;
        }
      }
      return true;
    });
  }, [news, filters]);

  const mostImpactfulNews = useMemo(() => {
    const analyzed = news.filter(n => n.analysis);
    const getScore = (n: AnalyzedNewsItem) => {
        if (!n.analysis) return 0;
        let base = 0;
        if (n.analysis.impact.level === ImpactLevel.HIGH) base = 300;
        else if (n.analysis.impact.level === ImpactLevel.MEDIUM) base = 200;
        else base = 100;
        return base + n.analysis.impact.confidence;
    };
    return [...analyzed].sort((a, b) => getScore(b) - getScore(a)).slice(0, 3);
  }, [news]);

  const autocompleteSuggestions = useMemo(() => {
    if (!newStockInput.trim()) return [];
    const search = newStockInput.toLowerCase();
    return MASTER_STOCK_LIST.filter(stock => 
      stock.toLowerCase().includes(search) && !watchlist.includes(stock.toUpperCase())
    ).slice(0, 5);
  }, [newStockInput, watchlist]);

  // Watchlist news filter (uses raw news data + watchlist, not affected by main feed filters)
  const watchlistNews = useMemo(() => {
      return news.filter(n => {
        if (n.analysis?.watchlistRelevance?.isRelevant) return true;
        const textToCheck = (n.title + ' ' + n.contentSnippet).toLowerCase();
        return watchlist.some(stock => textToCheck.includes(stock.toLowerCase()));
      });
  }, [news, watchlist]);

  const activeFilterCount = filters.sources.length + filters.sectors.length + filters.impactLevels.length + filters.sentiments.length;

  return (
    <div className="min-h-screen bg-background text-slate-100 pb-20">

      {/* Toast Notification */}
      {toastMessage && (
        <div className="fixed top-24 left-1/2 transform -translate-x-1/2 z-50 bg-slate-800/80 backdrop-blur-md border border-slate-600/50 text-slate-100 px-6 py-3 rounded-full shadow-lg flex items-center gap-2 animate-slideDownFade">
            <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
            <span className="text-sm font-medium">{toastMessage}</span>
        </div>
      )}

      {/* Top Bar */}
      <div className="sticky top-0 z-20 bg-background/80 backdrop-blur-md border-b border-slate-800 p-4">
        <div className="flex justify-between items-center">
            <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-gradient-to-tr from-blue-600 to-purple-600 flex items-center justify-center">
                <IconSparkles className="text-white w-5 h-5" />
            </div>
            <h1 className="font-bold text-lg tracking-tight">FinIntel<span className="text-primary font-light">India</span></h1>
            </div>
            <div className="flex items-center gap-3">
                 <button 
                    onClick={() => setShowFilterPanel(!showFilterPanel)}
                    className={`relative p-2 rounded-lg transition-colors ${showFilterPanel || activeFilterCount > 0 ? 'bg-slate-700 text-white' : 'text-slate-400 hover:text-white'}`}
                >
                    <IconFilter className="w-5 h-5" />
                    {activeFilterCount > 0 && (
                        <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-primary rounded-full border border-slate-900"></span>
                    )}
                 </button>
            </div>
        </div>
        {showFilterPanel && (
            <div className="mt-4">
                <FilterPanel 
                    filters={filters}
                    setFilters={setFilters}
                    availableSources={availableSources}
                    availableSectors={availableSectors}
                    onClose={() => setShowFilterPanel(false)}
                    resultCount={filteredNews.length}
                />
            </div>
        )}
      </div>

      {/* Main Content */}
      <main className="p-4 max-w-lg mx-auto w-full">

        {loading && news.length === 0 ? (
          <div className="flex flex-col items-center justify-center mt-20 space-y-4">
             <div className="w-8 h-8 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
             <p className="text-slate-400 text-sm">Fetching markets data...</p>
          </div>
        ) : (
          <>
            {/* Using display:none for view switching to prevent remounting/flashing */}

            {/* FEED VIEW */}
            <div style={{ display: activeView === 'feed' ? 'block' : 'none' }} className="space-y-6 animate-fadeIn">

                 {mostImpactfulNews.length > 0 && !showFilterPanel && (
                    <div className="bg-gradient-to-br from-slate-800 to-slate-900 border border-slate-700 rounded-xl p-4 shadow-lg relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-1 h-full bg-gradient-to-b from-yellow-400 to-orange-500"></div>
                        <h2 className="text-sm font-bold text-slate-200 uppercase tracking-wider mb-3 flex items-center gap-2">
                             <span className="text-yellow-400">⚡</span> Top Market Movers
                        </h2>
                        <div className="space-y-3">
                            {mostImpactfulNews.map(item => (
                                <div key={item.id} className="pb-3 border-b border-slate-700/50 last:border-0 last:pb-0 cursor-pointer">
                                    <div className="flex justify-between items-start">
                                        <h3 className="text-sm font-medium text-slate-100 line-clamp-1">{item.title}</h3>
                                        <span className={`text-[10px] px-1.5 py-0.5 rounded ml-2 whitespace-nowrap ${
                                            item.analysis?.impact.direction === 'Bullish' ? 'text-green-400 bg-green-400/10' : 
                                            item.analysis?.impact.direction === 'Bearish' ? 'text-red-400 bg-red-400/10' : 'text-slate-400 bg-slate-700'
                                        }`}>
                                            {item.analysis?.impact.level} Impact
                                        </span>
                                    </div>
                                    <p className="text-xs text-slate-400 mt-1 line-clamp-2">{item.analysis?.whyItMatters}</p>
                                </div>
                            ))}
                        </div>
                    </div>
                 )}

                 <div>
                    <div className="flex items-center justify-between mb-2">
                        <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
                            {activeFilterCount > 0 ? 'Filtered News' : 'Latest Headlines'}
